/* ── Supabase Client ── */
var _sb=null;
function getSb(){
  if(_sb)return _sb;
  var url=typeof process!=="undefined"&&process.env?process.env.NEXT_PUBLIC_SUPABASE_URL:null;
  var key=typeof process!=="undefined"&&process.env?process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY:null;
  if(!url||!key)return null;
  try{var{createClient}=require("@supabase/supabase-js");_sb=createClient(url,key);return _sb;}catch(e){return null;}
}

/* ── Persistence helpers ── */
async function loadUserData(userId){
  var sb=getSb();if(!sb)return null;
  try{
    var[{data:cards},{data:categories},{data:connections},{data:notes}]=await Promise.all([
      sb.from("cards").select("*").eq("user_id",userId),
      sb.from("categories").select("*").eq("user_id",userId),
      sb.from("connections").select("*").eq("user_id",userId),
      sb.from("notes").select("*").eq("user_id",userId)
    ]);
    if(!cards||cards.length===0)return null;
    return{cards:cards,categories:categories||[],connections:connections||[],notes:notes||[]};
  }catch(e){console.error("Load error:",e);return null;}
}
async function saveCard(userId,card){
  var sb=getSb();if(!sb)return;
  try{await sb.from("cards").upsert({...card,user_id:userId},{onConflict:"id,user_id"});}catch(e){console.error("Save card error:",e);}
}
async function deleteCardDb(userId,cardId){
  var sb=getSb();if(!sb)return;
  try{await sb.from("cards").delete().eq("id",cardId).eq("user_id",userId);}catch(e){}
}
async function saveCats(userId,cats){
  var sb=getSb();if(!sb)return;
  try{
    await sb.from("categories").delete().eq("user_id",userId);
    var rows=Object.entries(cats).map(function([name,conf]){return{user_id:userId,name:name,color:conf.color,canvas_x:conf.x,canvas_y:conf.y};});
    if(rows.length>0)await sb.from("categories").insert(rows);
  }catch(e){console.error("Save cats error:",e);}
}
async function saveConns(userId,conns){
  var sb=getSb();if(!sb)return;
  try{
    await sb.from("connections").delete().eq("user_id",userId);
    var rows=conns.map(function(c){return{user_id:userId,conn_id:c.id,from_card:c.from,to_card:c.to};});
    if(rows.length>0)await sb.from("connections").insert(rows);
  }catch(e){}
}
async function saveNotes(userId,notes){
  var sb=getSb();if(!sb)return;
  try{
    await sb.from("notes").delete().eq("user_id",userId);
    var rows=notes.map(function(n){return{user_id:userId,note_id:n.id,text:n.text,canvas_x:n.x,canvas_y:n.y,color:n.color};});
    if(rows.length>0)await sb.from("notes").insert(rows);
  }catch(e){}
}

/* ── Auto-position: place card in orbit around its category hub ── */
function autoPosition(card,cats,existingCards){
  var cat=cats[card.cat];
  if(!cat)return{cx:400+Math.random()*200,cy:400+Math.random()*200};
  var sibs=existingCards.filter(function(c){return c.cat===card.cat&&c.id!==card.id;});
  var idx=sibs.length;
  var angle=(idx/(Math.max(sibs.length,1)+1))*Math.PI*2-Math.PI/2+Math.random()*0.3;
  var radius=140+idx*18+Math.random()*30;
  return{cx:cat.x+Math.cos(angle)*radius,cy:cat.y+Math.sin(angle)*radius};
}

/* ── Drag-to-recategorize: check if card is near a category hub ── */
function findNearestCategory(cx,cy,cats,threshold){
  threshold=threshold||80;
  var best=null,bestDist=Infinity;
  Object.entries(cats).forEach(function([name,conf]){
    var dx=cx+70-conf.x,dy=cy+16-conf.y;
    var dist=Math.sqrt(dx*dx+dy*dy);
    if(dist<threshold&&dist<bestDist){bestDist=dist;best=name;}
  });
  return best;
}

/* ── Knowledge Graph data fields ── */
// Each card now carries:
//   concepts: string[]    — extracted key concepts/entities
//   semanticGroup: string — AI-assigned cluster ID
//   relStrength: {}       — {cardId: 0-1} auto-discovered relationship weights
// These are populated during ingest and used for future Knowledge Graph view.

function ScoreBreakdown(p){
  var s=p.card;var content=Math.min(100,Math.max(20,(s.details||[]).length*12+(s.pros||[]).length*10+(s.cons||[]).length*8));
  var fresh=100;var dy=Math.floor((Date.now()-new Date(s.date).getTime())/864e5);if(dy>180)fresh=30;else if(dy>90)fresh=50;else if(dy>30)fresh=75;
  var relevance=s.intent?80:50;if(s.pinned)relevance=Math.min(100,relevance+15);
  var ecosystem=s.score||50;
  var t=p.theme;
  function Bar(x){return <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:4}}>
    <span style={{fontSize:9,color:t.textMuted,width:55,textAlign:"right"}}>{x.label}</span>
    <div style={{flex:1,height:4,borderRadius:2,background:t.inputBg}}>
      <div style={{width:x.val+"%",height:"100%",borderRadius:2,background:x.val>=75?"#22c55e":x.val>=50?"#f59e0b":"#ef4444",transition:"width .5s"}}></div>
    </div>
    <span style={{fontSize:9,color:t.textSub,width:20}}>{x.val}</span>
  </div>;}
  return <div style={{padding:"8px 0"}}>
    <div style={{fontSize:9,fontWeight:700,letterSpacing:1,color:"#6366f1",marginBottom:6}}>RELEVANCY BREAKDOWN</div>
    <Bar label="Content" val={content}/>
    <Bar label="Freshness" val={fresh}/>
    <Bar label="Relevance" val={relevance}/>
    <Bar label="Ecosystem" val={ecosystem}/>
  </div>;
}

